224:   const Network::FilterChain*
225:   findFilterChain(uint16_t destination_port, const std::string& destination_address,
226:                   const std::string& server_name, const std::string& transport_protocol,
227:                   const std::vector<std::string>& application_protocols,
228:                   const std::string& source_address, uint16_t source_port,
229:                   std::string direct_source_address = "") {
230:     if (absl::StartsWith(destination_address, "/")) {
231:       local_address_ = *Network::Address::PipeInstance::create(destination_address);
232:     } else {
233:       local_address_ =
234:           Network::Utility::parseInternetAddressNoThrow(destination_address, destination_port);
235:     }
236:     socket_->connection_info_provider_->setLocalAddress(local_address_);
237: 
238:     socket_->connection_info_provider_->setRequestedServerName(server_name);
239:     ON_CALL(*socket_, requestedServerName()).WillByDefault(Return(absl::string_view(server_name)));
240:     ON_CALL(*socket_, detectedTransportProtocol())
241:         .WillByDefault(Return(absl::string_view(transport_protocol)));
242:     ON_CALL(*socket_, requestedApplicationProtocols())
243:         .WillByDefault(ReturnRef(application_protocols));
244: 
245:     if (absl::StartsWith(source_address, "/")) {
246:       remote_address_ = *Network::Address::PipeInstance::create(source_address);
247:     } else {
248:       remote_address_ = Network::Utility::parseInternetAddressNoThrow(source_address, source_port);
249:     }
250:     socket_->connection_info_provider_->setRemoteAddress(remote_address_);
251: 
252:     if (direct_source_address.empty()) {
253:       direct_source_address = source_address;
254:     }
255:     if (absl::StartsWith(direct_source_address, "/")) {
256:       direct_remote_address_ = *Network::Address::PipeInstance::create(direct_source_address);
257:     } else {
258:       direct_remote_address_ =
259:           Network::Utility::parseInternetAddressNoThrow(direct_source_address, source_port);
260:     }
261:     socket_->connection_info_provider_->setDirectRemoteAddressForTest(direct_remote_address_);
262: 
263:     return manager_->listeners().back().get().filterChainManager().findFilterChain(*socket_,
264:                                                                                    stream_info_);
265:   }
