  NiceMock<MockListenerComponentFactory>& listener_factory_;
  NiceMock<ProtobufMessage::MockValidationVisitor> validation_visitor;
  MockWorker* worker_ = new MockWorker();
  NiceMock<MockWorkerFactory> worker_factory_;
